  if(!configuredAdminEmails().includes(input.ownerEmail))throw new HttpsError("failed-precondition","再発防止責任者は本番管理者allowlistに登録されたメールに限ります。");if(input.status!=="completed"&&(dueMs<=now.toMillis()||dueMs>now.toMillis()+180*24*60*60_000))throw new HttpsError("invalid-argument","完了期限は現在より後、180日以内で指定してください。");
