async function syncAlertQueue(tx:FirebaseFirestore.Transaction,evidenceRef:FirebaseFirestore.DocumentReference,companyId:string,evidenceId:string,previous:ProductionEvidenceHealth|null,current:ProductionEvidenceHealth,now:Timestamp,notified:boolean):Promise<SlaEscalationNotice|null>{
  const currentRef=isAlertHealth(current)?evidenceRef.collection("alerts").doc(current.fingerprint):null;const previousRef=previous&&isAlertHealth(previous)&&previous.fingerprint!==current.fingerprint?evidenceRef.collection("alerts").doc(previous.fingerprint):null;const currentSnap=currentRef?await tx.get(currentRef):null;let escalation:SlaEscalationNotice|null=null;
  if(currentRef){const existing=currentSnap?.data()??{};const status=isAlertStatus(existing.status)?existing.status:"open";const nextAlert={...existing,status,firstDetectedAt:existing.firstDetectedAt??now,lastDetectedAt:now};const slaFields=slaStorageFields(current.fingerprint,current,nextAlert,now);const changedEscalation=slaFields.escalationLevel>0&&existing.lastEscalationKey!==slaFields.lastEscalationKey;tx.set(currentRef,{...alertPayload(companyId,evidenceId,current,now),...nextAlert,...slaFields,...(notified?{lastNotifiedAt:now}:{})},{merge:true});if(changedEscalation){escalation={alertFingerprint:current.fingerprint,priority:current.status==="critical"?"critical":"watch",level:slaFields.escalationLevel,label:slaFields.slaLabel,stage:slaFields.slaStage,assignedToEmail:textOrNull(existing.assignedToEmail)};tx.create(evidenceRef.collection("events").doc(),{companyId,evidenceId,releaseId:productionEvidenceReleaseId,type:"alert_sla_escalated",source:"scheduled_monitor",alertFingerprint:current.fingerprint,priority:escalation.priority,escalationLevel:escalation.level,slaStage:escalation.stage,slaLabel:escalation.label,assignedToEmail:escalation.assignedToEmail,createdAt:now});}}
  if(previousRef)tx.set(previousRef,{status:"resolved",resolvedAt:now,resolution:"health_transition",resolutionHealthFingerprint:current.fingerprint,slaStatus:"met",slaStage:"none",escalationLevel:0,lastEscalationKey:"none:0",updatedAt:now},{merge:true});return escalation;
}

